module shift_register (
    input clk,
    input sreset,
    input load_enable,
    input shift,
    input [23:0] data,
    output [23:0] q );reg [23:0] r_reg;

always @(posedge clk) begin
    if (sreset)
        r_reg <= 24'b0;
    else if (load_enable)
        r_reg <= data;
    else if (shift)
        r_reg <= {r_reg[22:0], 1'b0};
end

assign q = r_reg;

endmodule
